/**
 * tools/add-to-catalogue.ts
 *
 * CLI tool: fetches a materielelectrique.com product page and appends
 * the product to the specified catalogue file.
 *
 * Usage (PowerShell from project root):
 *   npx tsx tools/add-to-catalogue.ts <catalogue-name> <url>
 *
 * Examples:
 *   npx tsx tools/add-to-catalogue.ts catalogue.prises.legrand https://www.materielelectrique.com/prise-de-courant-legrand-celiane-2x2p-t-precablee-standard-francais-p-297670.html
 *   npx tsx tools/add-to-catalogue.ts catalogue.prises.legrand https://www.materielelectrique.com/prise-de-courant-legrand-celiane-4x2p-t-compacte-precablee-standard-francais-p-297691.html
 *
 * The catalogue file is created in config/ if it does not exist.
 * Duplicates (same id) are silently skipped.
 * Rate-limit delay is read from config/scraping.config.json.
 */

import { readFileSync, existsSync } from 'fs';
import { join } from 'path';
import { extractProductFromUrl } from './lib/extract-product-from-page';
import { cataloguePath, readCatalogue, writeCatalogue, buildMaterial, addMaterialToCatalogue } from './lib/catalogue-io';
import type { ScrapingConfig } from '../src/adapters/materielelectrique';
import { DEFAULT_SCRAPING_CONFIG } from '../src/adapters/materielelectrique';

// ── Load scraping config from file ────────────────────────────────────────────

function loadScrapingConfigFromFile(): ScrapingConfig {
  const configFile = join(process.cwd(), 'config', 'scraping.config.json');
  if (!existsSync(configFile)) {
    console.warn('⚠  config/scraping.config.json not found — using defaults');
    return DEFAULT_SCRAPING_CONFIG;
  }
  try {
    const raw = readFileSync(configFile, 'utf-8');
    const parsed = JSON.parse(raw) as Partial<ScrapingConfig>;
    const config = { ...DEFAULT_SCRAPING_CONFIG, ...parsed };
    return config;
  } catch {
    console.warn('⚠  Failed to parse config/scraping.config.json — using defaults');
    return DEFAULT_SCRAPING_CONFIG;
  }
}

// ── CLI ───────────────────────────────────────────────────────────────────────

async function main(): Promise<void> {
  const [catalogueName, url] = process.argv.slice(2);

  if (!catalogueName || !url) {
    console.error('Usage: npx tsx tools/add-to-catalogue.ts <catalogue-name> <url>');
    console.error('');
    console.error('Example:');
    console.error('  npx tsx tools/add-to-catalogue.ts catalogue.prises.legrand https://www.materielelectrique.com/...');
    process.exit(1);
  }

  if (!url.startsWith('https://www.materielelectrique.com/')) {
    console.error('❌  Only materielelectrique.com URLs are supported at this time.');
    process.exit(1);
  }

  const config = loadScrapingConfigFromFile();
  const filePath = cataloguePath(catalogueName);

  console.log(`  Catalogue : ${filePath}`);
  console.log(`  URL       : ${url}`);
  console.log(`⏱   Delay     : ${config.delayBetweenRequestsMs}ms between requests`);
  console.log('');
  console.log('⏳  Fetching product page...');

  let product;
  try {
    product = await extractProductFromUrl(url, config);
  } catch (err) {
    console.error(`❌  Failed to fetch/parse product: ${String(err)}`);
    process.exit(1);
  }

  console.log(`✅  Found: ${product.nom}`);
  console.log(`   Brand     : ${product.marque}`);
  console.log(`   Reference : ${product.reference}`);
  console.log(`   Category  : ${product.categorie}`);
  if (product.ean) console.log(`   EAN       : ${product.ean}`);
  console.log('');

  const catalogue = await readCatalogue(filePath);
  const material = buildMaterial(product);
  const added = addMaterialToCatalogue(catalogue, material);

  if (!added) {
    console.log(`⏭   Already in catalogue (id: ${material.id}) — skipped.`);
    return;
  }

  await writeCatalogue(filePath, catalogue);
  console.log(`✅  Added to ${filePath} (${catalogue.length} item(s) total)`);
}

main().catch((err) => {
  console.error('Unexpected error:', err);
  process.exit(1);
});

/**
 * tools/add-to-catalogue.ts
 *
 * CLI tool: fetches a materielelectrique.com product page and appends
 * the product to the specified catalogue file.
 *
 * Usage (PowerShell from project root):
 *   npx tsx tools/add-to-catalogue.ts <catalogue-name> <url>
 *
 * Examples:
 *   npx tsx tools/add-to-catalogue.ts catalogue.prises.legrand https://www.materielelectrique.com/prise-de-courant-legrand-celiane-2x2p-t-precablee-standard-francais-p-297670.html
 *   npx tsx tools/add-to-catalogue.ts catalogue.prises.legrand https://www.materielelectrique.com/prise-de-courant-legrand-celiane-4x2p-t-compacte-precablee-standard-francais-p-297691.html
 *
 * The catalogue file is created in config/ if it does not exist.
 * Duplicates (same id) are silently skipped.
 * Rate-limit delay is read from config/scraping.config.json.
 */

import { readFileSync, existsSync } from 'fs';
import { join } from 'path';
import { extractProductFromUrl } from './lib/extract-product-from-page';
import { cataloguePath, readCatalogue, writeCatalogue, buildMaterial, addMaterialToCatalogue } from './lib/catalogue-io';
import type { ScrapingConfig } from '../src/adapters/materielelectrique';
import { DEFAULT_SCRAPING_CONFIG } from '../src/adapters/materielelectrique';

// ── Load scraping config from file ────────────────────────────────────────────

function loadScrapingConfigFromFile(): ScrapingConfig {
  const configFile = join(process.cwd(), 'config', 'scraping.config.json');
  if (!existsSync(configFile)) {
    console.warn('⚠  config/scraping.config.json not found — using defaults');
    return DEFAULT_SCRAPING_CONFIG;
  }
  try {
    const raw = readFileSync(configFile, 'utf-8');
    const parsed = JSON.parse(raw) as Partial<ScrapingConfig>;
    const config = { ...DEFAULT_SCRAPING_CONFIG, ...parsed };
    return config;
  } catch {
    console.warn('⚠  Failed to parse config/scraping.config.json — using defaults');
    return DEFAULT_SCRAPING_CONFIG;
  }
}

// ── CLI ───────────────────────────────────────────────────────────────────────

async function main(): Promise<void> {
  const [catalogueName, url] = process.argv.slice(2);

  if (!catalogueName || !url) {
    console.error('Usage: npx tsx tools/add-to-catalogue.ts <catalogue-name> <url>');
    console.error('');
    console.error('Example:');
    console.error('  npx tsx tools/add-to-catalogue.ts catalogue.prises.legrand https://www.materielelectrique.com/...');
    process.exit(1);
  }

  if (!url.startsWith('https://www.materielelectrique.com/')) {
    console.error('❌  Only materielelectrique.com URLs are supported at this time.');
    process.exit(1);
  }

  const config = loadScrapingConfigFromFile();
  const filePath = cataloguePath(catalogueName);

  console.log(`  Catalogue : ${filePath}`);
  console.log(`  URL       : ${url}`);
  console.log(`⏱   Delay     : ${config.delayBetweenRequestsMs}ms between requests`);
  console.log('');
  console.log('⏳  Fetching product page...');

  let product;
  try {
    product = await extractProductFromUrl(url, config);
  } catch (err) {
    console.error(`❌  Failed to fetch/parse product: ${String(err)}`);
    process.exit(1);
  }

  console.log(`✅  Found: ${product.nom}`);
  console.log(`   Brand     : ${product.marque}`);
  console.log(`   Reference : ${product.reference}`);
  console.log(`   Category  : ${product.categorie}`);
  if (product.ean) console.log(`   EAN       : ${product.ean}`);
  console.log('');

  const catalogue = await readCatalogue(filePath);
  const material = buildMaterial(product);
  const added = addMaterialToCatalogue(catalogue, material);

  if (!added) {
    console.log(`⏭   Already in catalogue (id: ${material.id}) — skipped.`);
    return;
  }

  await writeCatalogue(filePath, catalogue);
  console.log(`✅  Added to ${filePath} (${catalogue.length} item(s) total)`);
  console.log(`\n  Don't forget to rebuild the app:  npm run build`);
}

main().catch((err) => {
  console.error('Unexpected error:', err);
  process.exit(1);
});

/**
 * tools/probe-rexel.ts
 *
 * Probes the Rexel price API.
 *
 * Usage:
 *   npx tsx tools/probe-rexel.ts <bearer-token> [sku] [branchId]
 *
 * Default SKU:      70569480 (Legrand Céliane 4x2P+T)
 * Default branchId: 4413
 *
 * The correct body shape (discovered from F12 DevTools on rexel.fr):
 *   {
 *     accountId,           ← from ERPCustomerID.accountNumber in JWT
 *     branchId,            ← user's local agency code, NOT in JWT
 *     pickupOptions:   { branchCode: branchId },
 *     deliveryOptions: { branchCode: branchId },
 *     stockReturnedOptions: { includeDCStock: true, includeBranchStock: true, includeDelay: true },
 *     includeLeasePrice: true,
 *     lines: [{ sku, quantity: { number: 1 } }],   ← quantity is an OBJECT
 *   }
 */

import axios from 'axios';

const API_URL = 'https://eu.dif.rexel.com/web/api/v3/product/priceandavailability';

// ── helpers ───────────────────────────────────────────────────────────────────

function extractFromJwt(jwt: string): { accountId: string; webshopId: string; apiKey: string } {
  try {
    const seg = jwt.split('.')[1] ?? '';
    const pad = (4 - (seg.length % 4)) % 4;
    const b64 = (seg + '='.repeat(pad)).replace(/-/g, '+').replace(/_/g, '/');
    const decoded = JSON.parse(Buffer.from(b64, 'base64').toString('utf-8')) as {
      ERPCustomerID?: { accountNumber?: string };
      WebshopID?: { webshopId?: string };
      api_key?: string;
    };
    return {
      accountId: decoded.ERPCustomerID?.accountNumber ?? '',
      webshopId: decoded.WebshopID?.webshopId ?? '',
      apiKey:    decoded.api_key ?? '',
    };
  } catch { return { accountId: '', webshopId: '', apiKey: '' }; }
}

async function probe(label: string, token: string, body: unknown): Promise<boolean> {
  const bodyStr = JSON.stringify(body);
  process.stdout.write(`\n[${label}] ${bodyStr.length} bytes → `);
  try {
    const res = await axios.post(API_URL, body, {
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
        'Content-Language': 'fr',
        Accept: 'application/json, text/plain, */*',
        'Accept-Language': 'fr,fr-FR;q=0.9,en-US;q=0.8,en;q=0.7',
        'x-banner': 'frx',
        Origin: 'https://www.rexel.fr',
        Referer: 'https://www.rexel.fr/',
      },
      timeout: 15_000,
    });
    const price = (res.data as { lines?: Array<{ prices?: Array<{ price?: { amount?: number }; priceLabel?: string }> }> })
      .lines?.[0]?.prices?.find((p) => p.priceLabel === 'UNIT_LIST_PRICE')?.price?.amount;
    console.log(`✅  HTTP ${res.status} — UNIT_LIST_PRICE = ${price ?? '(not found)'}`);
    console.log('    Body:', JSON.stringify(res.data).slice(0, 300));
    return true;
  } catch (err) {
    if (axios.isAxiosError(err)) {
      console.log(`❌  HTTP ${err.response?.status} — ${JSON.stringify(err.response?.data ?? err.message).slice(0, 300)}`);
    } else {
      console.log(`❌  ${String(err)}`);
    }
    return false;
  }
}

// ── main ──────────────────────────────────────────────────────────────────────

async function main(): Promise<void> {
  const [token, sku = '70569480', branchId = '4413', zipcode = '44880', city = 'SAUTRON'] = process.argv.slice(2);
  if (!token) {
    console.error('Usage: npx tsx tools/probe-rexel.ts <bearer-token> [sku] [branchId] [zipcode] [city]');
    process.exit(1);
  }

  const { accountId, webshopId, apiKey } = extractFromJwt(token);
  console.log(`\nProbing Rexel API`);
  console.log(`  SKU:        ${sku}`);
  console.log(`  accountId:  ${accountId || '(not found in JWT)'}`);
  console.log(`  webshopId:  ${webshopId || '(not found in JWT)'}`);
  console.log(`  apiKey:     ${apiKey || '(not found in JWT)'}`);
  console.log(`  branchId:   ${branchId}`);
  console.log(`  zipcode:    ${zipcode}`);
  console.log(`  city:       ${city}`);
  console.log('='.repeat(60));

  const ok = await probe('V_REAL (correct shape)', token, {
    accountId,
    branchId,
    pickupOptions:   { branchCode: branchId },
    deliveryOptions: {
      branchCode: branchId,
      location: { country: 'FR', zipcode, city },
    },
    stockReturnedOptions: {
      includeDCStock:     true,
      includeBranchStock: true,
      includeDelay:       true,
    },
    includeLeasePrice: true,
    lines: [{ sku, quantity: { number: 1 } }],
  });

  if (!ok) {
    console.log('\n── Fallback variants ──────────────────────────────────────');

    // V_F1 – without optional wrapper fields
    await probe('V_F1 minimal+accountId+branchId', token, {
      accountId,
      branchId,
      lines: [{ sku, quantity: { number: 1 } }],
    });

    // V_F2 – quantity as plain int (in case API changed again)
    await probe('V_F2 qty=int', token, {
      accountId,
      branchId,
      lines: [{ sku, quantity: 1 }],
    });

    // V_F3 – quantity as string (original attempt)
    await probe('V_F3 qty=str', token, {
      accountId,
      branchId,
      lines: [{ sku, quantity: '1' }],
    });

    // V_F4 – no branchId, just accountId + quantity object
    await probe('V_F4 no-branchId', token, {
      accountId,
      lines: [{ sku, quantity: { number: 1 } }],
    });
  }

  console.log('\n' + '='.repeat(60));
  console.log('Done.');
}

main().catch((e) => { console.error(e); process.exit(1); });

